import{ascending,groups}from"d3-array";import{BaseMixin}from"../base/base-mixin.js";const LABEL_CSS_CLASS="dc-grid-label",ITEM_CSS_CLASS="dc-grid-item",SECTION_CSS_CLASS="dc-grid-section dc-grid-group",GRID_CSS_CLASS="dc-grid-top";class DataGrid extends BaseMixin{constructor(e,t){super(e,t),this.configure({section:null,size:999,html:e=>"you need to provide an html() handling param:  "+JSON.stringify(e),sortBy:e=>e,order:ascending,beginSlice:0,endSlice:void 0,htmlSection:e=>`<div class='${SECTION_CSS_CLASS}'><h1 class='${LABEL_CSS_CLASS}'>${this._conf.keyAccessor(e)}</h1></div>`}),this._mandatoryAttributes(["dimension","section"])}configure(e){return super.configure(e),this}conf(){return this._conf}_doRender(){return this.selectAll("div."+GRID_CSS_CLASS).remove(),this._renderItems(this._renderSections()),this}_renderSections(){const e=this.root().selectAll("div."+GRID_CSS_CLASS).data(this._nestEntries(),e=>this._conf.keyAccessor(e)),t=e.enter().append("div").attr("class",GRID_CSS_CLASS);return this._conf.htmlSection&&t.html(e=>this._conf.htmlSection(e)),e.exit().remove(),t}_nestEntries(){let e=this.dataProvider().conf().dimension.top(this._conf.size);return e=e.sort((e,t)=>this._conf.order(this._conf.sortBy(e),this._conf.sortBy(t))).slice(this._conf.beginSlice,this._conf.endSlice),groups(e,this._conf.section).sort(this._conf.order).map(e=>({key:""+e[0],values:e[1]}))}_renderItems(e){let t=e.order().selectAll("div."+ITEM_CSS_CLASS).data(e=>e.values);return t.exit().remove(),t=t.enter().append("div").attr("class",ITEM_CSS_CLASS).html(e=>this._conf.html(e)).merge(t)}_doRedraw(){return this._doRender()}}export{DataGrid};